const stateOutput = $('Read Current State').first().json.stdout || 'Không đọc được CURRENT_STATE.md';
const progressOutput = $('Read Phase Progress').first().json.stdout || '0\n0';

const lines = progressOutput.trim().split('\n');
const done = parseInt(lines[0]) || 0;
const remaining = parseInt(lines[1]) || 0;

// Extract task đầu tiên từ CURRENT_STATE
const taskMatch = stateOutput.match(/Task đầu tiên[\s\S]*?→\s*(.+?)\n/);
const nextTask = taskMatch ? taskMatch[1].trim() : 'Xem CURRENT_STATE.md';

// Extract blockers
const blockerMatch = stateOutput.match(/Lỗi chưa xử lý[\s\S]*?\[ \]\s*(.+?)\n/);
const blocker = blockerMatch ? blockerMatch[1].trim() : 'Không có blocker';

const now = new Date();
const dateStr = now.toLocaleDateString('vi-VN', { 
  day: '2-digit', month: '2-digit', year: 'numeric',
  timeZone: 'Asia/Ho_Chi_Minh'
});

const message = `🟢 KICK-OFF ${dateStr} | Phase 0
━━━━━━━━━━━━━━━━━━━━━━

🎯 TASK TỐI NAY:
→ ${nextTask}

🐛 BLOCKER:
• ${blocker}

📍 PHASE 0 PROGRESS:
✅ Done: ${done} items
⏸ Còn lại: ${remaining} items

💬 Gõ /status để xem chi tiết
Gõ /done khi xong tối nay
Gõ /risk để xem risks cần xử lý`;

return [{ json: { 
  chat_id: '8498124621',
  text: message
} }];
